#include <iostream>\n#include <vector>\n#include <set>\n\nclass Graph {\n public:\n  explicit Graph(int n, const std::vector<std::pair<int, int>>& edges) : n_(n + 1) {\n    table_.resize(n_);\n    Build(edges);\n  }\n\n  const std::set<int>& GetBridges() {\n    return bridges_;\n  }\n\n private:\n  void Build(const std::vector<std::pair<int, int>>& edges) {\n    for (int i = 0; i < static_cast<int>(edges.size()); i++) {\n      int a = edges[i].first;\n      int b = edges[i].second;\n      if (a == b) {\n        continue;\n      }\n      table_[a].emplace_back(b, i + 1);\n      table_[b].emplace_back(a, i + 1);\n    }\n\n    used_.resize(n_, false);\n    d_.resize(n_, -1);\n    h_.resize(n_, -1);\n\n    for (int i = 1; i < n_; i++) {\n      if (!used_[i]) {\n        Dfs(i);\n      }\n    }\n  }\n\n  void Dfs(int v, int parent = -1) {\n    used_[v] = true;\n    if (parent == -1) {\n      d_[v] = h_[v] = 0;\n    } else {\n      d_[v] = h_[v] = h_[parent] + 1;\n    }\n    for (const std::pair<int, int>& t : table_[v]) {\n      int u = t.first;\n      int edge = t.second;\n      if (u == parent) {\n        continue;\n      }\n      if (used_[u]) {\n        d_[v] = std::min(d_[v], h_[u]);\n      } else {\n        Dfs(u, v);\n        d_[v] = std::min(d_[v], d_[u]);\n        if (h_[v] < d_[u]) {\n          bridges_.insert(edge);\n        }\n      }\n    }\n  }\n\n  int n_;\n  std::vector<bool> used_;\n  std::vector<int> h_;\n  std::vector<int> d_;\n  std::set<int> bridges_;\n  std::vector<std::vector<std::pair<int, int>>> table_;\n};\n\nint main() {\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n\n  std::vector<std::pair<int, int>> edges(m);\n  for (int i = 0; i < m; i++) {\n    std::cin >> edges[i].first >> edges[i].second;\n  }\n\n  Graph g(n, edges);\n\n  std::cout << g.GetBridges().size() << std::endl;\n  for (int i : g.GetBridges()) {\n    std::cout << i << std::endl;\n  }\n  return 0;\n}